import{_ as t,o as h,c as i,a0 as l}from"./chunks/framework.jwovEGr5.js";const e=JSON.parse('{"title":"Nhập dữ liệu","description":"","frontmatter":{"title":"Nhập dữ liệu"},"headers":[],"relativePath":"data-import.md","filePath":"data-import.md"}'),a={name:"data-import.md"};function o(r,n,g,u,c,p){return h(),i("div",null,[...n[0]||(n[0]=[l('<h1 id="nhap-du-lieu" tabindex="-1">Nhập dữ liệu <a class="header-anchor" href="#nhap-du-lieu" aria-label="Permalink to &quot;Nhập dữ liệu&quot;">​</a></h1><p><strong>Nhập dữ liệu (Data Import)</strong> trong ABNERP cho phép nhập hàng loạt dữ liệu từ các nguồn bên ngoài vào hệ thống một cách nhanh chóng và chính xác. Công cụ này đặc biệt hữu ích trong giai đoạn triển khai ban đầu hoặc khi cần đồng bộ dữ liệu từ hệ thống cũ.</p><h2 id="chuan-bi-du-lieu" tabindex="-1">Chuẩn bị dữ liệu <a class="header-anchor" href="#chuan-bi-du-lieu" aria-label="Permalink to &quot;Chuẩn bị dữ liệu&quot;">​</a></h2><p>Trước khi nhập, hãy đảm bảo dữ liệu nguồn đã được làm sạch và đúng định dạng:</p><ul><li><strong>Định dạng tệp hỗ trợ</strong>: Excel (.xlsx) và CSV (.csv)</li><li><strong>Mã hóa (Encoding)</strong>: UTF-8 (khuyến nghị) hoặc các mã hóa phổ biến khác</li><li><strong>Cấu trúc dữ liệu</strong>: mỗi dòng là một bản ghi, mỗi cột là một trường dữ liệu</li><li><strong>Loại bỏ trùng lặp</strong>: kiểm tra và loại bỏ dữ liệu trùng trước khi nhập</li></ul><h2 id="tai-mau-nhap" tabindex="-1">Tải mẫu nhập <a class="header-anchor" href="#tai-mau-nhap" aria-label="Permalink to &quot;Tải mẫu nhập&quot;">​</a></h2><p>ABNERP tự động tạo <strong>Mẫu nhập (Template)</strong> cho từng loại dữ liệu:</p><ol><li>Vào công cụ <strong>Nhập dữ liệu (Data Import Tool)</strong></li><li>Chọn loại <strong>Tài liệu (Document Type)</strong> muốn nhập (Khách hàng, Mặt hàng, Đơn hàng, v.v.)</li><li>Nhấn <strong>Tải mẫu (Download Template)</strong></li><li>Mẫu Excel được tải về với đầy đủ tên cột và hướng dẫn bằng tiếng Việt</li></ol><p>Mẫu bao gồm: cột dữ liệu, cột bắt buộc (có đánh dấu *), và ví dụ minh họa ở dòng đầu tiên.</p><h2 id="anh-xa-truong" tabindex="-1">Ánh xạ trường <a class="header-anchor" href="#anh-xa-truong" aria-label="Permalink to &quot;Ánh xạ trường&quot;">​</a></h2><p>Sau khi điền dữ liệu vào mẫu, quá trình nhập sẽ tự động phát hiện và ánh xạ các cột trong tệp với các trường trong hệ thống. Người dùng có thể can thiệp thủ công để:</p><ul><li><strong>Khớp tên cột</strong>: ánh xạ cột trong tệp với trường hệ thống nếu tên khác nhau</li><li><strong>Bỏ qua cột</strong>: chọn không nhập một số cột nhất định</li><li><strong>Giá trị mặc định</strong>: thiết lập giá trị mặc định cho trường không có trong tệp</li><li><strong>Chuyển đổi dữ liệu</strong>: định dạng lại dữ liệu (ví dụ: ngày tháng, số)</li></ul><h2 id="quy-trinh-nhap" tabindex="-1">Quy trình nhập <a class="header-anchor" href="#quy-trinh-nhap" aria-label="Permalink to &quot;Quy trình nhập&quot;">​</a></h2><p>Sau khi thiết lập ánh xạ, nhấn <strong>Bắt đầu nhập (Start Import)</strong>. Hệ thống sẽ:</p><ol><li><strong>Xác thực</strong>: kiểm tra từng dòng dữ liệu — xác nhận các trường bắt buộc, định dạng hợp lệ</li><li><strong>Tạo bản ghi</strong>: tạo bản ghi trong hệ thống cho các dòng hợp lệ</li><li><strong>Báo cáo kết quả</strong>: hiển thị số bản ghi thành công, số lỗi và chi tiết từng lỗi</li></ol><h3 id="nhat-ky-nhap" tabindex="-1">Nhật ký nhập <a class="header-anchor" href="#nhat-ky-nhap" aria-label="Permalink to &quot;Nhật ký nhập&quot;">​</a></h3><p>Sau khi nhập, hệ thống lưu lại <strong>Nhật ký nhập (Import Log)</strong> với đầy đủ thông tin:</p><ul><li>Tổng số dòng đã nhập</li><li>Số dòng thành công và thất bại</li><li>Danh sách lỗi chi tiết cho từng dòng (dòng số, tên cột, giá trị lỗi, nguyên nhân)</li><li>Liên kết đến các bản ghi đã được tạo thành công</li></ul><p>Người dùng có thể xuất báo cáo lỗi để sửa lại dữ liệu và nhập lại mà không cần bắt đầu từ đầu.</p><h3 id="meo-nhap-du-lieu-hieu-qua" tabindex="-1">Mẹo nhập dữ liệu hiệu quả <a class="header-anchor" href="#meo-nhap-du-lieu-hieu-qua" aria-label="Permalink to &quot;Mẹo nhập dữ liệu hiệu quả&quot;">​</a></h3><ul><li>Nhập tối đa 5000 dòng mỗi lần để đảm bảo hiệu suất</li><li>Nhập dữ liệu tham chiếu trước (Khách hàng, Nhà cung cấp, Mặt hàng) trước khi nhập dữ liệu giao dịch (Đơn hàng, Hóa đơn)</li><li>Sử dụng tính năng <strong>Xem trước (Preview)</strong> để kiểm tra dữ liệu trước khi nhập chính thức</li><li>Luôn sao lưu dữ liệu trước khi thực hiện nhập hàng loạt</li></ul>',21)])])}const s=t(a,[["render",o]]);export{e as __pageData,s as default};
